logger = logging.getLogger(__name__)


class LoggerAdapter(logging.LoggerAdapter):
    "Add username and remote IP to the logged message"

    def process(self, msg: str, kwargs):
        extra: dict[str, str] = self.extra
        msg = '[%s@%s] ' % (extra['user'], extra['ip']) + msg
        return msg, kwargs


def get_request_logger(request, logger):
    "Get a specialized `logger` for a Pyramid `request`"

    extra = dict(
        ip=request.environ.get('HTTP_X_REAL_IP', request.client_addr),
        user=request.session.get('user_name') or 'anonymous'
    )
    return LoggerAdapter(logger, extra)


def unauthorized_for_guest(f):
    """Prevent `guest` users to perform the operation."""

    @wraps(f)
    def wrapper(request):
        t = translator(request)

        log = get_request_logger(request, logger)

        if 'user_name' in request.session:
            if not request.session['is_guest']:
                return f(request)

            message = t(
                _('Guest users are not allowed to perform this operation, sorry!')
            )
        else:
            message = t(_('You must logon to perform this operation!'))

        log.warning('Not allowed to perform %s', f.__name__)

        return dict(success=False, message=message)

    return wrapper


def only_for_admins(f):
    """Ensure only admins can perform the operation."""

    @wraps(f)
    def wrapper(request):
        t = translator(request)

        log = get_request_logger(request, logger)

        if 'user_name' in request.session:
            if request.session['is_admin']:
                return f(request)

            message = t(
                _('Only admins are allowed to perform this operation, sorry!')
            )
        else:
            message = t(_('You must logon to perform this operation!'))

        log.warning('Not allowed to perform %s', f.__name__)

        return dict(success=False, message=message)

    return wrapper


def compute_elapsed_time(since: int | None, max_minutes: int) -> int | None:
    "Compute elapsed milliseconds since `since` timestamp, up to `max_minutes`."

    if since is None:
        elapsed = None
    else:
        elapsed = int(time() * 1000) - since
        if elapsed > max_minutes * 60 * 1000:  # pragma: no cover
            elapsed = None
    return elapsed


json_decode = Decoder(datetime_mode=DM_ISO8601, number_mode=NM_NATIVE).__call__
'Custom JSON decoder.'


json_encode = Encoder(
    datetime_mode=DM_ISO8601 | DM_NAIVE_IS_UTC,
    number_mode=NM_NATIVE | NM_DECIMAL,
    ensure_ascii=False,
).__call__
'Custom JSON encoder.'


# Quick and dirty countermeasure to limit data theft, making it more difficult for bots and
# unethic individuals to download the whole database: enforce a limit of 168 records / 4 pages
# of 42 records each


class ExcessiveOffset(OperationAborted):
    pass


class UnacceptableOffset(OperationAborted):
    pass


PQFCA = ProxiedBase.prepareQueryFromConditionsAndArgs

def limitedPQFCA(self, session, conditions, args):
    max_recs_per_page = 42
    max_pages = 4
    max_limit = max_recs_per_page * max_pages

    start = args.get('start')
    if start is not None:
        start = int(start)
        max_start = max_limit - max_recs_per_page

        if start > max_limit * 2:
            raise UnacceptableOffset("Make do with what you've gotten")
        elif start > max_limit:
            raise ExcessiveOffset(
                '"%d records ought to be enough for anybody!", Bill said' % max_limit
            )

        args['start'] = min(start, max_start)

    limit = args.get('limit')
    if limit is None:
        args['limit'] = max_limit
    else:
        args['limit'] = min(int(limit), max_limit)

    return PQFCA(self, session, conditions, args)

ProxiedBase.prepareQueryFromConditionsAndArgs = limitedPQFCA


def _expose_call(self, method):
    @wraps(method)
    def workhorse(request):
        adapt = method().send if isgeneratorfunction(method) else False

        session = self.create_session(request)
        options = self.proxy_kwargs.copy()
        options.update(self.extract_parameters(request))
        conditions = ()

        with transaction.manager:
            if adapt:
                try:
                    adapt(None)
                    options = adapt((request, options))
                except StopIteration:
                    logger.exception(
                        'Possibly wrongly implemented generator function'
                        ' (does it "return" instead of "yield"?)'
                    )
                    return dict(success=False, message='Internal error')
                except OperationAborted as e:
                    logger.error('Operation aborted: %s', str(e))
                    return dict(success=False, message=str(e))

                if isinstance(options, tuple):
                    options, conditions = options

            if request.method == 'GET':
                try:
                    result = self.proxie(session, request, *conditions, **options)
                except ExcessiveOffset as e:
                    logger.warning('Attempt to bite off more than they can chew: %s', str(e))
                    # Here we cheat: tell the UI we got at least 1 empty record, to avoid grid
                    # lock, even when we deliberately caused the error above
                    return dict(success=True, message=str(e), count=1, root=[{}])
                except UnacceptableOffset as e:
                    logger.warning('Way too high offset: %s', request.path_qs)
                    response = request.response
                    response.status = 406  # Not acceptable
                    response.text = str(e)
                    return response
                except OperationAborted as e:
                    logger.error('Operation aborted: %s', str(e))
                    return dict(success=False, message=str(e))
            else:
                handler = getattr(self, request.method, None)
                if handler is None:
                    raise NotImplementedError(
                        'Could not handle %s request' % request.method)
                result = handler(session, request, **options)

            if adapt:
                try:
                    result = adapt(result)
                except StopIteration:
                    logger.exception(
                        'Possibly wrongly implemented generator function'
                        ' (does it "return" instead of "yield"?)'
                    )
                    result = dict(success=False, message='Internal error')
                except OperationAborted as e:
                    logger.error('Operation aborted: %s', str(e))
                    result = dict(success=True, message=str(e), count=1, root=[{}])
            else:
                try:
                    result = method(request, result)
                except OperationAborted as e:
                    logger.error('Operation aborted: %s', str(e))
                    result = dict(success=False, message=str(e))

            return result

    return workhorse

expose.__call__ = _expose_call


register_json_decoder_encoder(json_decode, json_encode)
expose.create_session = staticmethod(lambda request: request.dbsession)
expose.save_changes = staticmethod(save_changes)
